$dir = "D:/Plocha/projekty/esn-uwb-web/outstatic/content/partners"
Get-ChildItem "$dir/*.md" | ForEach-Object {
    $bytes = [System.IO.File]::ReadAllBytes\($_.FullName\)
    $hasBOM = \($bytes.Length -ge 3 -and $bytes[0] -eq 0xEF -and $bytes[1] -eq 0xBB -and $bytes[2] -eq 0xBF\)

    # Check for double-encoded UTF-8 \(bytes C3 followed by common second bytes\)
    # This catches mojibake like sequences where UTF-8 was re-encoded as UTF-8
    $suspicious = $false
    $suspiciousPositions = @\(\)
    for \($i = 0; $i -lt $bytes.Length - 1; $i++\) {
        # C3 xx patterns that are suspicious \(Latin chars encoded twice\)
        if \($bytes[$i] -eq 0xC3 -and $bytes[$i+1] -ge 0x80 -and $bytes[$i+1] -le 0xBF\) {
            # This is normal UTF-8 for accented chars, skip
        }
        # Check for C4/C5 followed by high bytes \(Czech diacritics double-encoded\)
        if \($bytes[$i] -eq 0xC3 -and \($i+2\) -lt $bytes.Length -and $bytes[$i+1] -ge 0x80 -and $bytes[$i+2] -ge 0x80\) {
            # Could be double encoding - flag it
        }
    }

    $status = ""
    if \($hasBOM\) { $status += "HAS-BOM" }
    if \(-not $hasBOM\) { $status = "OK \(no BOM\)" }
    Write-Output \("{0}: {1}, first 6 bytes: {2}" -f $_.Name, $status, \(\($bytes[0..5] | ForEach-Object { $_.ToString\("X2"\) }\) -join " "\)\)
}
PSEOF)

Bash(/tmp/check_garbled.ps1 << 'PSEOF'
$dir = "D:/Plocha/projekty/esn-uwb-web/outstatic/content/partners"
Get-ChildItem "$dir/*.md" | ForEach-Object {
    $content = [System.IO.File]::ReadAllText\($_.FullName, [System.Text.Encoding]::UTF8\)
    # Look for sequences where C3/C4/C5 bytes got interpreted as individual chars
    # Common mojibake: two-char sequences where first is in U+00C0-U+00C5 range 
    # and second is in U+0080-U+00BF range
    $found = @\(\)
    for \($i = 0; $i -lt $content.Length - 1; $i++\) {
        $c1 = [int]$content[$i]
        $c2 = [int]$content[$i+1]
        # Detect double-encoded UTF-8 appearing as Latin chars
        if \(\($c1 -ge 0xC0 -and $c1 -le 0xC5\) -and \($c2 -ge 0x80 -and $c2 -le 0xBF\)\) {
            $ctx = $content.Substring\([Math]::Max\(0, $i-10\), [Math]::Min\(25, $content.Length - [Math]::Max\(0, $i-10\)\)\)
            $ctx = $ctx -replace "`r`n", " " -replace "`n", " "
            $found += "pos $i : U+{0:X4} U+{1:X4} context=[{2}]" -f $c1, $c2, $ctx
        }
    }
    if \($found.Count -gt 0\) {
        Write-Output \("=== {0}: {1} suspicious sequences ===" -f $_.Name, $found.Count\)
        $found | Select-Object -First 5 | ForEach-Object { Write-Output "  $_" }
        if \($found.Count -gt 5\) { Write-Output "  ... and $\($found.Count - 5\) more" }
    } else {
        Write-Output \("{0}: CLEAN \(no garbled chars detected\)" -f $_.Name\)
    }
}
PSEOF)

